import{_ as t,o,c as i,a2 as n}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Theme Options","description":"FXT Theme Options","frontmatter":{"title":"Theme Options","description":"FXT Theme Options","weight":90,"extra":{"order":90},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/theme-options"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/theme-options"}],["meta",{"property":"og:title","content":"Theme Options"}],["meta",{"property":"og:description","content":"FXT Theme Options"}],["meta",{"name":"twitter:title","content":"Theme Options"}],["meta",{"name":"twitter:description","content":"FXT Theme Options"}]]},"headers":[],"relativePath":"docs/fxt/theme-options.md","filePath":"docs/fxt/theme-options.md"}'),s={name:"docs/fxt/theme-options.md"};function a(r,e,l,p,c,h){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="theme-options" tabindex="-1">Theme Options <a class="header-anchor" href="#theme-options" aria-label="Permalink to &quot;Theme Options&quot;">​</a></h1><p>FXT theme provides comprehensive options to customize your website through the <strong>FXT Options</strong> admin panel.</p><hr><h2 id="accessing-theme-options" tabindex="-1">Accessing Theme Options <a class="header-anchor" href="#accessing-theme-options" aria-label="Permalink to &quot;Accessing Theme Options&quot;">​</a></h2><p>To access theme options:</p><ol><li>In WordPress dashboard, click on <strong>FXT Options</strong> in the left sidebar</li><li>You&#39;ll be taken to the main options page with multiple sections</li></ol><hr><h2 id="main-options-sections" tabindex="-1">Main Options Sections <a class="header-anchor" href="#main-options-sections" aria-label="Permalink to &quot;Main Options Sections&quot;">​</a></h2><h3 id="license-key" tabindex="-1">License Key <a class="header-anchor" href="#license-key" aria-label="Permalink to &quot;License Key&quot;">​</a></h3><p>Register your theme to receive updates.</p><p><strong>Location</strong>: License Key section in FXT Options</p><p><strong>Settings</strong>:</p><ul><li>License Key: Enter your license key from DinoMatic account</li><li>Activate/Deactivate License: Manage license status</li></ul><h3 id="broker-options" tabindex="-1">Broker Options <a class="header-anchor" href="#broker-options" aria-label="Permalink to &quot;Broker Options&quot;">​</a></h3><p>Configure broker-related settings and features.</p><p><strong>Location</strong>: Broker Options section in FXT Options</p><p><strong>Settings</strong>:</p><ul><li>Broker Page Slug: Set the URL slug for broker pages</li><li>Rich Snippets: Enable/disable structured data for broker pages</li><li>Rich Snippet Author: Set the author for rich snippets</li><li>Author Block: Enable/disable author information blocks</li><li>Author Full Block: Enable/disable full author blocks</li><li>Table of Contents: Enable/disable TOC on broker pages</li></ul><h3 id="page-options" tabindex="-1">Page Options <a class="header-anchor" href="#page-options" aria-label="Permalink to &quot;Page Options&quot;">​</a></h3><p>Configure settings for regular pages.</p><p><strong>Location</strong>: Page Options section in FXT Options</p><p><strong>Settings</strong>:</p><ul><li>Author Block: Enable/disable author information blocks on pages</li><li>Author Full Block: Enable/disable full author blocks on pages</li><li>Table of Contents: Enable/disable TOC on pages</li></ul><h3 id="post-options" tabindex="-1">Post Options <a class="header-anchor" href="#post-options" aria-label="Permalink to &quot;Post Options&quot;">​</a></h3><p>Configure settings for blog posts.</p><p><strong>Location</strong>: Post Options section in FXT Options</p><p><strong>Settings</strong>:</p><ul><li>Author Block: Enable/disable author information blocks on posts</li><li>Author Full Block: Enable/disable full author blocks on posts</li><li>Table of Contents: Enable/disable TOC on posts</li></ul><h3 id="social-media-options" tabindex="-1">Social Media Options <a class="header-anchor" href="#social-media-options" aria-label="Permalink to &quot;Social Media Options&quot;">​</a></h3><p>Configure social media links and settings.</p><p><strong>Location</strong>: Social Media Options section in FXT Options</p><p><strong>Settings</strong>:</p><ul><li>Social Media Links: Add links to your social media profiles</li><li>These links will be displayed on the website</li></ul><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/theme-strings">Theme Strings</a></p>',36)])])}const m=t(s,[["render",a]]);export{u as __pageData,m as default};
